const esc = (str) => (str ?? '').replace(/'/g, "''");

const FREEMAIL = new Set([
  'gmail.com','googlemail.com','outlook.com','hotmail.com','hotmail.es',
  'live.com','yahoo.com','yahoo.es','icloud.com','me.com','mac.com',
  'protonmail.com','proton.me','aol.com','zoho.com','mail.com',
  'gmx.com','gmx.es','yandex.com','tutanota.com','fastmail.com'
]);

const mailboxEmail = $('Config').first().json.mailbox_email.toLowerCase();
const mailboxId    = $('Upsert mailbox').first().json.id;

const results = [];

for (const item of $input.all()) {
  const msg = item.json;

  const rawFrom    = msg.From    ?? '';
  const rawTo      = msg.To      ?? '';
  const rawCc      = msg.Cc      ?? msg.CC ?? '';
  const rawSubject = msg.Subject ?? msg.subject ?? '';

  // Robust address parser
  const parseAddresses = (raw, role) => {
    if (!raw) return [];
    return raw.split(/,(?=(?:[^"]*"[^"]*")*[^"]*$)/).map(addr => {
      addr = addr.trim();
      const angleMatch = addr.match(/<([^>]+)>/);
      if (angleMatch) {
        const email = angleMatch[1].trim().toLowerCase();
        const namePart = addr.slice(0, addr.indexOf('<')).replace(/^["'\s]+|["'\s]+$/g, '').trim();
        return { email, name: esc(namePart), role };
      }
      const bareEmail = addr.replace(/^["'\s]+|["'\s]+$/g, '').toLowerCase();
      return { email: bareEmail, name: '', role };
    }).filter(p => p.email && p.email.includes('@'));
  };

  const participants = [
    ...parseAddresses(rawFrom, 'from'),
    ...parseAddresses(rawTo,   'to'),
    ...parseAddresses(rawCc,   'cc')
  ];

  const fromEntry  = participants.find(p => p.role === 'from');
  const fromEmail  = fromEntry?.email ?? '';
  const fromDomain = fromEmail.includes('@') ? fromEmail.split('@')[1] : '';

  const allRecipients = participants
    .filter(p => p.role === 'to' || p.role === 'cc')
    .map(p => p.email);

  let direction;
  if (fromEmail === mailboxEmail) {
    direction = 'team_to_client';
  } else if (allRecipients.includes(mailboxEmail)) {
    direction = 'client_to_team';
  } else {
    direction = 'internal';
  }

  // For team_to_client: resolve from RECIPIENT, not sender
  let resolveEmail, resolveDomain;
  if (direction === 'team_to_client') {
    const extRecipient = participants.find(
      p => (p.role === 'to' || p.role === 'cc') && p.email !== mailboxEmail
    );
    resolveEmail  = extRecipient?.email ?? '';
    resolveDomain = resolveEmail.includes('@') ? resolveEmail.split('@')[1] : '';
  } else {
    resolveEmail  = fromEmail;
    resolveDomain = fromDomain;
  }

  // Freemail: don't resolve by domain (would merge unrelated people)
  if (FREEMAIL.has(resolveDomain)) {
    resolveDomain = '';
  }

  const cleanSubject = rawSubject
    .replace(/^(Re|RE|Fwd|FWD|Fw|FW):\s*/g, '')
    .trim();

  const bodyText = msg.snippet ?? '';

  const sentAt = msg.internalDate
    ? new Date(parseInt(msg.internalDate)).toISOString()
    : new Date().toISOString();

  // Resolve display name (from the person we're resolving against)
  let resolveDisplayName = '';
  if (direction === 'team_to_client') {
    const extRecipient = participants.find(
      p => (p.role === 'to' || p.role === 'cc') && p.email !== mailboxEmail
    );
    resolveDisplayName = extRecipient?.name ?? '';
  } else {
    resolveDisplayName = fromEntry?.name ?? '';
  }
  results.push({
    json: {
      provider_message_id: msg.id,
      provider_thread_id:  msg.threadId,
      internet_message_id: '',
      subject:             esc(cleanSubject),
      raw_subject:         esc(rawSubject),
      snippet:             esc(msg.snippet ?? ''),
      body_text:           esc(bodyText),
      sent_at:             sentAt,
      direction,
      participants,
      from_email:          fromEmail,
      from_domain:         fromDomain,
      resolve_email:       resolveEmail,
      resolve_domain:      resolveDomain,
      mailbox_id:          mailboxId,
      mailbox_email:       mailboxEmail,
      resolve_display_name: resolveDisplayName,
      raw_payload:         JSON.stringify(msg).replace(/'/g, "''")
    }
  });
}

return results;

// Merge resolve-client result back into the normalized message
const normalized = $('Normalitza email').item.json;
const clientRow  = $input.item.json;

const clientId = clientRow?.client_id ?? null;

return [{
  json: {
    ...normalized,
    client_id: clientId,
    needs_manual_review: clientId === null
  }
}];

// Attach thread_id to the message data
const msg      = $('Merge client_id').item.json;
const threadRow = $input.item.json;

return [{
  json: {
    ...msg,
    thread_id: threadRow.thread_id
  }
}];

// Build one row per participant, attached to the new message_id
const msg       = $('Attach thread_id').item.json;
const messageRow = $input.item.json;

return msg.participants.map(p => ({
  json: {
    message_id:  messageRow.message_id,
    thread_id:   msg.thread_id,
    email:       p.email,
    name:        p.name,
    role:        p.role
  }
}));

// Collect highest historyId across the entire batch
const allItems = $input.all();
const historyIds = allItems
  .map(i => parseInt($('Normalitza email').item?.json?.history_id ?? '0'))
  .filter(n => !isNaN(n));

const highest = historyIds.length > 0 ? Math.max(...historyIds).toString() : '0';
const mailboxEmail = $('Config').first().json.mailbox_email;

return [{ json: { highest_history_id: highest, mailbox_email: mailboxEmail } }];
